// TRM desde datos.gov.co (Superfinanciera) con fallback a open.er-api.com.
// Ambas fuentes son gratuitas y no requieren API key.
const fetchDatosGov = async () => {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.datos.gov.co/resource/32sa-8pi3.json',
    qs: { '$limit': '1', '$order': 'vigenciadesde DESC' },
    headers: { 'User-Agent': 'alebas-cotizador/1.0', 'Accept': 'application/json' },
    returnFullResponse: true,
    json: true,
  });
  if (r.statusCode !== 200) throw new Error(`datos.gov.co HTTP ${r.statusCode}`);
  const rows = Array.isArray(r.body) ? r.body : r.body;
  if (!rows?.length) throw new Error('datos.gov.co: sin registros');
  const v = parseFloat(rows[0].valor);
  if (!v || v < 1000 || v > 20000) throw new Error(`TRM fuera de rango: ${v}`);
  return { cop_per_usd: v, date: (rows[0].vigenciadesde || '').slice(0, 10), source: 'datos.gov.co (Superfinanciera)' };
};

const fetchErApi = async () => {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://open.er-api.com/v6/latest/USD',
    headers: { 'User-Agent': 'alebas-cotizador/1.0' },
    returnFullResponse: true,
    json: true,
  });
  if (r.statusCode !== 200) throw new Error(`ExchangeRate-API HTTP ${r.statusCode}`);
  const cop = r.body?.rates?.COP;
  if (!cop || cop < 1000) throw new Error(`COP rate inválida: ${cop}`);
  return { cop_per_usd: +cop.toFixed(2), date: new Date().toISOString().slice(0, 10), source: 'open.er-api.com' };
};

let data;
try {
  data = await fetchDatosGov();
} catch (e1) {
  try {
    data = await fetchErApi();
    data.fallback = true;
    data.fallbackReason = e1.message;
  } catch (e2) {
    return [{ json: { ok: false, reason: 'upstream_error', detail: `Fuente 1: ${e1.message} | Fuente 2: ${e2.message}` } }];
  }
}
return [{ json: { ok: true, ...data, syncedAt: new Date().toISOString() } }];
